struct editorSyntaxState {
	enum editorSyntaxLanguage language;
	TSParser *parser;
	TSTree *tree;
};

struct editorSyntaxQueryCacheEntry {
	int load_attempted;
	TSQuery *query;
	enum editorSyntaxHighlightClass *capture_classes;
	uint32_t capture_count;
};

static struct editorSyntaxQueryCacheEntry g_c_highlight_query_cache = {
	.load_attempted = 0,
	.query = NULL,
	.capture_classes = NULL,
	.capture_count = 0
};

static struct editorSyntaxQueryCacheEntry g_shell_highlight_query_cache = {
	.load_attempted = 0,
	.query = NULL,
	.capture_classes = NULL,
	.capture_count = 0
};

