static const TSLanguage *editorSyntaxLanguageObject(enum editorSyntaxLanguage language);

static int editorSyntaxLengthFitsTreeSitter(size_t len) {
	return len <= UINT32_MAX;
}

static int editorSyntaxCaptureNameHasPrefix(const char *name, size_t len, const char *prefix) {
	size_t prefix_len = strlen(prefix);
	if (len < prefix_len) {
		return 0;
	}
	return strncmp(name, prefix, prefix_len) == 0;
}

static enum editorSyntaxHighlightClass editorSyntaxClassFromCaptureName(const char *name,
		size_t len) {
	if (name == NULL || len == 0) {
		return EDITOR_SYNTAX_HL_NONE;
	}

	if (editorSyntaxCaptureNameHasPrefix(name, len, "comment")) {
		return EDITOR_SYNTAX_HL_COMMENT;
	}
	if (editorSyntaxCaptureNameHasPrefix(name, len, "keyword")) {
		return EDITOR_SYNTAX_HL_KEYWORD;
	}
	if (editorSyntaxCaptureNameHasPrefix(name, len, "type")) {
		return EDITOR_SYNTAX_HL_TYPE;
	}
	if (editorSyntaxCaptureNameHasPrefix(name, len, "function")) {
		return EDITOR_SYNTAX_HL_FUNCTION;
	}
	if (editorSyntaxCaptureNameHasPrefix(name, len, "command")) {
		return EDITOR_SYNTAX_HL_FUNCTION;
	}
	if (editorSyntaxCaptureNameHasPrefix(name, len, "string") ||
			editorSyntaxCaptureNameHasPrefix(name, len, "character")) {
		return EDITOR_SYNTAX_HL_STRING;
	}
	if (editorSyntaxCaptureNameHasPrefix(name, len, "number") ||
			editorSyntaxCaptureNameHasPrefix(name, len, "float")) {
		return EDITOR_SYNTAX_HL_NUMBER;
	}
	if (editorSyntaxCaptureNameHasPrefix(name, len, "constant") ||
			editorSyntaxCaptureNameHasPrefix(name, len, "boolean") ||
			editorSyntaxCaptureNameHasPrefix(name, len, "variable") ||
			editorSyntaxCaptureNameHasPrefix(name, len, "property")) {
		return EDITOR_SYNTAX_HL_CONSTANT;
	}
	if (editorSyntaxCaptureNameHasPrefix(name, len, "preproc") ||
			editorSyntaxCaptureNameHasPrefix(name, len, "preprocessor")) {
		return EDITOR_SYNTAX_HL_PREPROCESSOR;
	}
	if (editorSyntaxCaptureNameHasPrefix(name, len, "operator")) {
		return EDITOR_SYNTAX_HL_OPERATOR;
	}
	if (editorSyntaxCaptureNameHasPrefix(name, len, "punctuation")) {
		return EDITOR_SYNTAX_HL_PUNCTUATION;
	}
	if (editorSyntaxCaptureNameHasPrefix(name, len, "delimiter")) {
		return EDITOR_SYNTAX_HL_PUNCTUATION;
	}

	return EDITOR_SYNTAX_HL_NONE;
}

static char *editorSyntaxReadFileDup(const char *path, size_t *len_out) {
	if (len_out != NULL) {
		*len_out = 0;
	}
	FILE *fp = fopen(path, "rb");
	if (fp == NULL) {
		return NULL;
	}

	size_t cap = 1024;
	size_t len = 0;
	char *buf = malloc(cap);
	if (buf == NULL) {
		fclose(fp);
		return NULL;
	}

	for (;;) {
		if (len + 1 >= cap) {
			size_t new_cap = cap * 2;
			if (new_cap <= cap) {
				free(buf);
				fclose(fp);
				return NULL;
			}
			char *grown = realloc(buf, new_cap);
			if (grown == NULL) {
				free(buf);
				fclose(fp);
				return NULL;
			}
			buf = grown;
			cap = new_cap;
		}

		size_t remaining = cap - len - 1;
		size_t nread = fread(buf + len, 1, remaining, fp);
		len += nread;
		if (nread < remaining) {
			if (ferror(fp)) {
				free(buf);
				fclose(fp);
				return NULL;
			}
			break;
		}
	}

	fclose(fp);
	buf[len] = '\0';
	if (len_out != NULL) {
		*len_out = len;
	}
	return buf;
}

static int editorSyntaxCompileQuery(enum editorSyntaxLanguage language, const char *query_source,
		size_t query_len, TSQuery **query_out) {
	const TSLanguage *ts_language = editorSyntaxLanguageObject(language);
	if (ts_language == NULL || query_source == NULL || query_out == NULL ||
			!editorSyntaxLengthFitsTreeSitter(query_len)) {
		return 0;
	}

	uint32_t error_offset = 0;
	TSQueryError error_type = TSQueryErrorNone;
	TSQuery *query = ts_query_new(ts_language, query_source, (uint32_t)query_len, &error_offset,
			&error_type);
	if (query == NULL) {
		(void)error_offset;
		(void)error_type;
		return 0;
	}

	*query_out = query;
	return 1;
}

static int editorSyntaxPopulateCaptureClasses(TSQuery *query,
		enum editorSyntaxHighlightClass **capture_classes_out, uint32_t *capture_count_out) {
	if (capture_classes_out == NULL || capture_count_out == NULL || query == NULL) {
		return 0;
	}
	*capture_classes_out = NULL;
	*capture_count_out = 0;

	uint32_t capture_count = ts_query_capture_count(query);
	enum editorSyntaxHighlightClass *capture_classes = NULL;
	if (capture_count > 0) {
		size_t bytes = (size_t)capture_count * sizeof(*capture_classes);
		capture_classes = malloc(bytes);
		if (capture_classes == NULL) {
			return 0;
		}
		for (uint32_t i = 0; i < capture_count; i++) {
			capture_classes[i] = EDITOR_SYNTAX_HL_NONE;
		}
		for (uint32_t i = 0; i < capture_count; i++) {
			uint32_t name_len = 0;
			const char *name = ts_query_capture_name_for_id(query, i, &name_len);
			capture_classes[i] = editorSyntaxClassFromCaptureName(name, name_len);
		}
	}

	*capture_classes_out = capture_classes;
	*capture_count_out = capture_count;
	return 1;
}

static int editorSyntaxEnsureQueryCache(struct editorSyntaxQueryCacheEntry *cache,
		enum editorSyntaxLanguage language, const char *query_path,
		const char *fallback_query) {
	if (cache == NULL || query_path == NULL || fallback_query == NULL) {
		return 0;
	}
	if (cache->load_attempted) {
		return cache->query != NULL;
	}
	cache->load_attempted = 1;

	TSQuery *query = NULL;
	size_t file_len = 0;
	char *file_query = editorSyntaxReadFileDup(query_path, &file_len);
	if (file_query != NULL) {
		(void)editorSyntaxCompileQuery(language, file_query, file_len, &query);
		free(file_query);
	}

	if (query == NULL) {
		(void)editorSyntaxCompileQuery(language, fallback_query, strlen(fallback_query), &query);
	}
	if (query == NULL) {
		return 0;
	}

	enum editorSyntaxHighlightClass *capture_classes = NULL;
	uint32_t capture_count = 0;
	if (!editorSyntaxPopulateCaptureClasses(query, &capture_classes, &capture_count)) {
		ts_query_delete(query);
		return 0;
	}

	cache->query = query;
	cache->capture_classes = capture_classes;
	cache->capture_count = capture_count;
	return 1;
}

static int editorSyntaxEnsureHighlightQueryForC(void) {
	return editorSyntaxEnsureQueryCache(&g_c_highlight_query_cache, EDITOR_SYNTAX_C,
			"vendor/tree_sitter/grammars/c/queries/highlights.scm",
			editor_builtin_c_highlights_query);
}

static int editorSyntaxEnsureHighlightQueryForShell(void) {
	return editorSyntaxEnsureQueryCache(&g_shell_highlight_query_cache,
			EDITOR_SYNTAX_SHELL,
			"vendor/tree_sitter/grammars/bash/queries/highlights.scm",
			editor_builtin_shell_highlights_query);
}

static int editorSyntaxEnsureHighlightQuery(enum editorSyntaxLanguage language) {
	switch (language) {
		case EDITOR_SYNTAX_C:
			return editorSyntaxEnsureHighlightQueryForC();
		case EDITOR_SYNTAX_SHELL:
			return editorSyntaxEnsureHighlightQueryForShell();
		case EDITOR_SYNTAX_NONE:
		default:
			return 0;
	}
}

static const struct editorSyntaxQueryCacheEntry *editorSyntaxQueryCacheForLanguage(
		enum editorSyntaxLanguage language) {
	switch (language) {
		case EDITOR_SYNTAX_C:
			return &g_c_highlight_query_cache;
		case EDITOR_SYNTAX_SHELL:
			return &g_shell_highlight_query_cache;
		case EDITOR_SYNTAX_NONE:
		default:
			return NULL;
	}
}

static const TSLanguage *editorSyntaxLanguageObject(enum editorSyntaxLanguage language) {
	switch (language) {
		case EDITOR_SYNTAX_C:
			return tree_sitter_c();
		case EDITOR_SYNTAX_SHELL:
			return tree_sitter_bash();
		case EDITOR_SYNTAX_NONE:
		default:
			return NULL;
	}
}

static int editorSyntaxIsShellInterpreterName(const char *token, size_t len) {
	return (len == 2 && strncasecmp(token, "sh", 2) == 0) ||
			(len == 4 && strncasecmp(token, "bash", 4) == 0) ||
			(len == 3 && strncasecmp(token, "zsh", 3) == 0) ||
			(len == 3 && strncasecmp(token, "ksh", 3) == 0);
}

static int editorSyntaxTokenFromLine(const char *line, size_t line_len, size_t *idx,
		const char **token_out, size_t *token_len_out) {
	if (line == NULL || idx == NULL || token_out == NULL || token_len_out == NULL) {
		return 0;
	}

	size_t i = *idx;
	while (i < line_len && isspace((unsigned char)line[i])) {
		i++;
	}
	if (i >= line_len) {
		*idx = i;
		return 0;
	}

	size_t start = i;
	while (i < line_len && !isspace((unsigned char)line[i])) {
		i++;
	}

	*idx = i;
	*token_out = &line[start];
	*token_len_out = i - start;
	return 1;
}

static enum editorSyntaxLanguage editorSyntaxDetectLanguageFromShebang(
		const char *first_line) {
	if (first_line == NULL || first_line[0] != '#' || first_line[1] != '!') {
		return EDITOR_SYNTAX_NONE;
	}

	size_t line_len = strlen(first_line);
	size_t idx = 2;
	const char *token = NULL;
	size_t token_len = 0;
	if (!editorSyntaxTokenFromLine(first_line, line_len, &idx, &token, &token_len)) {
		return EDITOR_SYNTAX_NONE;
	}

	const char *base = token;
	for (size_t i = 0; i < token_len; i++) {
		if (token[i] == '/') {
			base = &token[i + 1];
		}
	}
	size_t base_len = token_len - (size_t)(base - token);

	if (editorSyntaxIsShellInterpreterName(base, base_len)) {
		return EDITOR_SYNTAX_SHELL;
	}

	if (base_len == 3 && strncasecmp(base, "env", 3) == 0) {
		for (;;) {
			if (!editorSyntaxTokenFromLine(first_line, line_len, &idx, &token, &token_len)) {
				break;
			}
			if (token_len > 0 && token[0] == '-') {
				continue;
			}

			base = token;
			for (size_t i = 0; i < token_len; i++) {
				if (token[i] == '/') {
					base = &token[i + 1];
				}
			}
			base_len = token_len - (size_t)(base - token);
			if (editorSyntaxIsShellInterpreterName(base, base_len)) {
				return EDITOR_SYNTAX_SHELL;
			}
			break;
		}
	}

	return EDITOR_SYNTAX_NONE;
}

static int editorSyntaxFilenameIsExtensionless(const char *filename) {
	if (filename == NULL || filename[0] == '\0') {
		return 1;
	}

	const char *base = strrchr(filename, '/');
	if (base != NULL) {
		base++;
	} else {
		base = filename;
	}
	if (base[0] == '\0') {
		return 0;
	}
	if (strchr(base, '.') == NULL) {
		return 1;
	}
	if (base[0] == '.' && strchr(base + 1, '.') == NULL) {
		return 1;
	}
	return 0;
}

enum editorSyntaxLanguage editorSyntaxDetectLanguageFromFilename(const char *filename) {
	if (filename == NULL || filename[0] == '\0') {
		return EDITOR_SYNTAX_NONE;
	}

	const char *dot = strrchr(filename, '.');
	if (dot != NULL && (strcmp(dot, ".c") == 0 || strcmp(dot, ".h") == 0)) {
		return EDITOR_SYNTAX_C;
	}
	if (dot != NULL &&
			(strcmp(dot, ".sh") == 0 || strcmp(dot, ".bash") == 0 ||
					strcmp(dot, ".zsh") == 0 || strcmp(dot, ".ksh") == 0)) {
		return EDITOR_SYNTAX_SHELL;
	}

	const char *base = strrchr(filename, '/');
	if (base != NULL) {
		base++;
	} else {
		base = filename;
	}
	if (strcmp(base, ".bashrc") == 0 || strcmp(base, ".zshrc") == 0 ||
			strcmp(base, ".profile") == 0 || strcmp(base, ".bash_profile") == 0 ||
			strcmp(base, ".bash_login") == 0 || strcmp(base, ".kshrc") == 0) {
		return EDITOR_SYNTAX_SHELL;
	}

	return EDITOR_SYNTAX_NONE;
}

enum editorSyntaxLanguage editorSyntaxDetectLanguageFromFilenameAndFirstLine(
		const char *filename, const char *first_line) {
	enum editorSyntaxLanguage from_filename = editorSyntaxDetectLanguageFromFilename(filename);
	if (from_filename != EDITOR_SYNTAX_NONE) {
		return from_filename;
	}
	if (!editorSyntaxFilenameIsExtensionless(filename)) {
		return EDITOR_SYNTAX_NONE;
	}

	return editorSyntaxDetectLanguageFromShebang(first_line);
}

struct editorSyntaxState *editorSyntaxStateCreate(enum editorSyntaxLanguage language) {
	const TSLanguage *ts_language = editorSyntaxLanguageObject(language);
	if (ts_language == NULL) {
		return NULL;
	}

	struct editorSyntaxState *state = malloc(sizeof(*state));
	if (state == NULL) {
		return NULL;
	}
	state->language = language;
	state->parser = ts_parser_new();
	state->tree = NULL;
	if (state->parser == NULL) {
		free(state);
		return NULL;
	}
	if (!ts_parser_set_language(state->parser, ts_language)) {
		ts_parser_delete(state->parser);
		free(state);
		return NULL;
	}

	return state;
}

void editorSyntaxStateDestroy(struct editorSyntaxState *state) {
	if (state == NULL) {
		return;
	}
	if (state->tree != NULL) {
		ts_tree_delete(state->tree);
	}
	if (state->parser != NULL) {
		ts_parser_delete(state->parser);
	}
	free(state);
}

int editorSyntaxStateParseFull(struct editorSyntaxState *state, const char *source, size_t len) {
	if (state == NULL || state->parser == NULL || source == NULL || !editorSyntaxLengthFitsTreeSitter(len)) {
		return 0;
	}

	TSTree *new_tree = ts_parser_parse_string(state->parser, NULL, source, (uint32_t)len);
	if (new_tree == NULL) {
		return 0;
	}

	if (state->tree != NULL) {
		ts_tree_delete(state->tree);
	}
	state->tree = new_tree;
	return 1;
}

int editorSyntaxStateApplyEditAndParse(struct editorSyntaxState *state,
		const struct editorSyntaxEdit *edit,
		const char *source,
		size_t len) {
	if (state == NULL || state->parser == NULL || state->tree == NULL || edit == NULL ||
			source == NULL || !editorSyntaxLengthFitsTreeSitter(len)) {
		return 0;
	}

	TSInputEdit ts_edit = {
		.start_byte = edit->start_byte,
		.old_end_byte = edit->old_end_byte,
		.new_end_byte = edit->new_end_byte,
		.start_point = {.row = edit->start_point.row, .column = edit->start_point.column},
		.old_end_point = {.row = edit->old_end_point.row, .column = edit->old_end_point.column},
		.new_end_point = {.row = edit->new_end_point.row, .column = edit->new_end_point.column},
	};
	ts_tree_edit(state->tree, &ts_edit);

	TSTree *new_tree = ts_parser_parse_string(state->parser, state->tree, source, (uint32_t)len);
	if (new_tree == NULL) {
		return 0;
	}

	ts_tree_delete(state->tree);
	state->tree = new_tree;
	return 1;
}

int editorSyntaxStateHasTree(const struct editorSyntaxState *state) {
	return state != NULL && state->tree != NULL;
}

const char *editorSyntaxStateRootType(const struct editorSyntaxState *state) {
	if (!editorSyntaxStateHasTree(state)) {
		return NULL;
	}

	TSNode root = ts_tree_root_node(state->tree);
	return ts_node_type(root);
}

enum editorSyntaxLanguage editorSyntaxStateLanguage(const struct editorSyntaxState *state) {
	if (state == NULL) {
		return EDITOR_SYNTAX_NONE;
	}
	return state->language;
}

int editorSyntaxStateCollectCapturesForRange(const struct editorSyntaxState *state,
		uint32_t start_byte, uint32_t end_byte,
		struct editorSyntaxCapture *captures, int max_captures, int *count_out) {
	if (count_out != NULL) {
		*count_out = 0;
	}
	if (state == NULL || state->tree == NULL || start_byte >= end_byte || max_captures < 0 ||
			(max_captures > 0 && captures == NULL)) {
		return 0;
	}

	if (!editorSyntaxEnsureHighlightQuery(state->language)) {
		return 1;
	}
	const struct editorSyntaxQueryCacheEntry *cache =
			editorSyntaxQueryCacheForLanguage(state->language);
	if (cache == NULL || cache->query == NULL) {
		return 1;
	}

	TSQueryCursor *cursor = ts_query_cursor_new();
	if (cursor == NULL) {
		return 0;
	}

	ts_query_cursor_set_byte_range(cursor, start_byte, end_byte);
	TSNode root = ts_tree_root_node(state->tree);
	ts_query_cursor_exec(cursor, cache->query, root);

	int count = 0;
	TSQueryMatch match;
	uint32_t capture_idx = 0;
	while (ts_query_cursor_next_capture(cursor, &match, &capture_idx)) {
		TSQueryCapture capture = match.captures[capture_idx];
		if (capture.index >= cache->capture_count || cache->capture_classes == NULL) {
			continue;
		}
		enum editorSyntaxHighlightClass highlight_class =
				cache->capture_classes[capture.index];
		if (highlight_class == EDITOR_SYNTAX_HL_NONE) {
			continue;
		}

		uint32_t capture_start = ts_node_start_byte(capture.node);
		uint32_t capture_end = ts_node_end_byte(capture.node);
		if (capture_end <= capture_start) {
			continue;
		}
		if (capture_end <= start_byte || capture_start >= end_byte) {
			continue;
		}

		if (capture_start < start_byte) {
			capture_start = start_byte;
		}
		if (capture_end > end_byte) {
			capture_end = end_byte;
		}
		if (capture_end <= capture_start) {
			continue;
		}

		if (count < max_captures) {
			captures[count].start_byte = capture_start;
			captures[count].end_byte = capture_end;
			captures[count].highlight_class = highlight_class;
		}
		count++;
	}

	ts_query_cursor_delete(cursor);
	if (count_out != NULL) {
		*count_out = count > max_captures ? max_captures : count;
	}
	return 1;
}

void editorSyntaxReleaseSharedResources(void) {
	if (g_c_highlight_query_cache.query != NULL) {
		ts_query_delete(g_c_highlight_query_cache.query);
		g_c_highlight_query_cache.query = NULL;
	}
	free(g_c_highlight_query_cache.capture_classes);
	g_c_highlight_query_cache.capture_classes = NULL;
	g_c_highlight_query_cache.capture_count = 0;
	g_c_highlight_query_cache.load_attempted = 0;

	if (g_shell_highlight_query_cache.query != NULL) {
		ts_query_delete(g_shell_highlight_query_cache.query);
		g_shell_highlight_query_cache.query = NULL;
	}
	free(g_shell_highlight_query_cache.capture_classes);
	g_shell_highlight_query_cache.capture_classes = NULL;
	g_shell_highlight_query_cache.capture_count = 0;
	g_shell_highlight_query_cache.load_attempted = 0;
}
